/// <summary>
/// A stage card in the stage board.  Automatically applies the
/// <c>"stageButton"</c> style class so the theme selectors
/// (<c>Button.stageButton</c>) match without theme changes.
/// Rich child content is provided via the existing
/// <see cref="DataTemplate"/> in <c>StageBoard.axaml</c>.
/// </summary>
public partial class StageCardButton : ContentControl
{
    private readonly Button _innerButton;
    private bool _suppressContentRedirect;

    /// <summary>
    /// Identifies the <see cref="Command"/> styled property.
    /// Forwarded to the inner <see cref="Button"/>.
    /// </summary>
    public static readonly StyledProperty<ICommand?> CommandProperty =
        AvaloniaProperty.Register<StageCardButton, ICommand?>(
            nameof(Command));

    /// <summary>
    /// Identifies the <see cref="CommandParameter"/> styled property.
    /// Forwarded to the inner <see cref="Button"/>.
    /// </summary>
    public static readonly StyledProperty<object?> CommandParameterProperty =
        AvaloniaProperty.Register<StageCardButton, object?>(
            nameof(CommandParameter));

    static StageCardButton()
    {
        CommandProperty.Changed.AddClassHandler<StageCardButton>(OnCommandChanged);
        CommandParameterProperty.Changed.AddClassHandler<StageCardButton>(OnCommandParameterChanged);
    }

    public StageCardButton()
    {
        _innerButton = new Button();
        _innerButton.Classes.Add("stageButton");

        _suppressContentRedirect = true;
        Content = _innerButton;
        _suppressContentRedirect = false;
    }

    /// <summary>
    /// The command to invoke when the button is clicked.
    /// Forwarded to the inner <see cref="Button"/>.
    /// </summary>
    public ICommand? Command
    {
        get => GetValue(CommandProperty);
        set => SetValue(CommandProperty, value);
    }

    /// <summary>
    /// The parameter to pass to <see cref="Command"/>.
    /// Forwarded to the inner <see cref="Button"/>.
    /// </summary>
    public object? CommandParameter
    {
        get => GetValue(CommandParameterProperty);
        set => SetValue(CommandParameterProperty, value);
    }

    /// <summary>
    /// Occurs when the button is clicked.  The event source is this
    /// <see cref="StageCardButton"/>, not the inner <see cref="Button"/>.
    /// </summary>
    public event EventHandler<RoutedEventArgs>? Click
    {
        add => _innerButton.Click += value;
        remove => _innerButton.Click -= value;
    }

    /// <inheritdoc />
    protected override void OnPropertyChanged(AvaloniaPropertyChangedEventArgs change)
    {
        base.OnPropertyChanged(change);

        if (change.Property == ContentProperty)
        {
            if (_suppressContentRedirect)
                return;

            // Forward consumer-supplied Content to the inner Button.
            _innerButton.Content = change.NewValue;

            // Restore the inner Button as the ContentControl's content.
            _suppressContentRedirect = true;
            Content = _innerButton;
            _suppressContentRedirect = false;
        }
    }

    private static void OnCommandChanged(StageCardButton button, AvaloniaPropertyChangedEventArgs e)
    {
        button._innerButton.Command = (ICommand?)e.NewValue;
    }

    private static void OnCommandParameterChanged(StageCardButton button, AvaloniaPropertyChangedEventArgs e)
    {
        button._innerButton.CommandParameter = e.NewValue;
    }
}

